class Solution:
  def validatePortMappings(self, portMappings):
    # Initialize an empty set to keep track of the host ports in use
    hostPortsInUse = set()
    # Iterate over the port mappings for each container
    for container in portMappings:
      # Check if the host port is already in use
      for portMapping in portMappings[container]:
        # Check if the host port is valid
        if (portMapping[0] >= 0 and portMapping[0] <= 65535 and portMapping[1] >= 0 and portMapping[1] <= 65535 and portMapping[0] not in hostPortsInUse):
          hostPortsInUse.add(portMapping[0])
        else:
          return False
    # Return true if all port mappings are valid, false otherwise
    return True
